mapper.select:
SELECT r.record_id, r.plate_number, r.space_id, r.entry_time, r.exit_time, r.fee_amount, r.pay_status, r.pay_time, s.space_code FROM parking_record r LEFT JOIN parking_space s ON r.space_id = s.space_id
AND r.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND r.exit_time IS NULL
AND r.exit_time IS NOT NULL
AND r.pay_status = #{payStatus}
AND DATE(r.entry_time) >= #{startDate}
AND DATE(r.entry_time) <= #{endDate}
ORDER BY r.entry_time DESC
